import json;d=json.load(open('data.json'))
def sol(g):
  g=[r[:] for r in g]
  H=len(g);W=len(g[0])
  from collections import deque
  # flood fill 0-cells reachable from border
  reach=[[0]*W for _ in range(H)]
  q=deque()
  for r in range(H):
   for c in range(W):
    if (r in(0,H-1) or c in(0,W-1)) and g[r][c]==0:
     q.append((r,c));reach[r][c]=1
  while q:
    r,c=q.popleft()
    for dr,dc in[(1,0),(-1,0),(0,1),(0,-1)]:
      nr,nc=r+dr,c+dc
      if 0<=nr<H and 0<=nc<W and g[nr][nc]==0 and not reach[nr][nc]:
        reach[nr][nc]=1;q.append((nr,nc))
  for r in range(H):
   for c in range(W):
    if g[r][c]==0 and not reach[r][c]:g[r][c]=4
  return g
ok=0;bad=0
for ex in d['train']+d['test']:
  if sol(ex['input'])==ex['output']:ok+=1
  else:bad+=1;
print('ok',ok,'bad',bad)
"

