def gp(o,r,c):return o[r][c] if 0<=r<len(o)and 0<=c<len(o[r]) else -1
from collections import deque
def sol_box(g):
    H=len(g);o=[r[:]for r in g];seen=[[0]*H for _ in range(H)]
    for r in range(H):
        for c in range(H):
            if g[r][c]==0 and not seen[r][c]:
                comp=[];q=deque([(r,c)]);seen[r][c]=1
                while q:
                    y,x=q.popleft();comp.append((y,x))
                    for a,b in((1,0),(-1,0),(0,1),(0,-1)):
                        ny,nx=y+a,x+b
                        if 0<=ny<H and 0<=nx<H and g[ny][nx]==0 and not seen[ny][nx]:seen[ny][nx]=1;q.append((ny,nx))
                ys=[y for y,x in comp];xs=[x for y,x in comp]
                y0,y1,x0,x1=min(ys),max(ys),min(xs),max(xs)
                if len(comp)==(y1-y0+1)*(x1-x0+1):
                    ok=all(gp(g,yy,x0-1)>0 and gp(g,yy,x1+1)>0 for yy in range(y0,y1+1)) and \
                       all(gp(g,y0-1,xx)>0 and gp(g,y1+1,xx)>0 for xx in range(x0,x1+1))
                    if ok:
                        for y,x in comp:o[y][x]=4
    return o
# add single is_surrounded pass after box fill
def sol2(g):
    o=sol_box(g);H=len(o)
    for r in range(H):
        for c in range(H):
            if o[r][c]==0 and all(gp(o,r+a,c+b)>0 for a,b in((1,0),(0,1),(-1,0),(0,-1))):o[r][c]=4
    return o
random.seed(0)
ok1=ok2=0;N=3000
for _ in range(N):
    ex=gen.generate();inp=[r[:]for r in ex['input']]
    if sol_box([r[:]for r in inp])==ex['output']:ok1+=1
    if sol2([r[:]for r in inp])==ex['output']:ok2+=1
print('box only:',ok1,'/',N,'   box+single-pass:',ok2,'/',N)
