import importlib.util,common,random
spec=importlib.util.spec_from_file_location('gen','gen.py');gen=importlib.util.module_from_spec(spec);spec.loader.exec_module(gen)
def gp(o,r,c):return o[r][c] if 0<=r<len(o)and 0<=c<len(o[r]) else -1
from collections import deque
def sol(g):
    H=len(g);o=[r[:]for r in g];seen=[[0]*H for _ in range(H)]
    for r in range(H):
        for c in range(H):
            if g[r][c]==0 and not seen[r][c]:
                comp=[];q=deque([(r,c)]);seen[r][c]=1
                while q:
                    y,x=q.popleft();comp.append((y,x))
                    for a,b in((1,0),(-1,0),(0,1),(0,-1)):
                        ny,nx=y+a,x+b
                        if 0<=ny<H and 0<=nx<H and g[ny][nx]==0 and not seen[ny][nx]:seen[ny][nx]=1;q.append((ny,nx))
                ys=[y for y,x in comp];xs=[x for y,x in comp]
                y0,y1,x0,x1=min(ys),max(ys),min(xs),max(xs)
                if len(comp)==(y1-y0+1)*(x1-x0+1):
                    # full ring including corners must be green
                    ring=True
                    for yy in range(y0-1,y1+2):
                        if gp(g,yy,x0-1)<=0 or gp(g,yy,x1+1)<=0:ring=False
                    for xx in range(x0-1,x1+2):
                        if gp(g,y0-1,xx)<=0 or gp(g,y1+1,xx)<=0:ring=False
                    if ring:
                        for y,x in comp:o[y][x]=4
    return o
random.seed(0)
ok=0;N=5000
for _ in range(N):
    ex=gen.generate();inp=[r[:]for r in ex['input']]
    if sol([r[:]for r in inp])==ex['output']:ok+=1
print('box + full-ring(incl corners):',ok,'/',N)
